		},
		onShow() {
		  // йҖҡзҹҘ tabbar жӣҙж–°зҠ¶жҖҒ
		    uni.$emit('switch-tab');
			const token = uni.getStorageSync('token');

			// иҝӣе…ҘйЎөйқўз»ҹдёҖе…ҲеҒңж—§иҪ®иҜўпјҢйҒҝе…ҚеҸ еҠ 
