				this.kefuLoginData = cachedKefuData;
			}

			// жңӘзҷ»еҪ•пјҡз«ӢеҚіе…ій—ӯйӘЁжһ¶еұҸе№¶жҳҫзӨәзҷ»еҪ•еј•еҜј
			if (!token) {
				this.loading1 = false;
				this.isShowList = false;
				this.sessions = [];
			}

			uni.getSystemInfo({
				success: (result) => {
					that.contentTop = result.statusBarHeight + 44 + 'px'
				}
			})
			that.showLoadMore = true
			if (uni.getStorageSync('newchatMsg') != true) {
				if (uni.getStorageSync('token') != '' && uni.getStorageSync('token') != undefined) {
					that.page = 1
					that.sessions = []
					that.isLoadingSessions = true;  // ж Үи®°жӯЈеңЁеҠ иҪҪ
					that.goodsList();
				} else {
					this.loading1 = false
					that.sessions = []
				}
			}
		},
		onHide() {
			// йЎөйқўйҡҗи—Ҹж—¶еҒңжӯўиҪ®иҜўе’Ңеҝғи·іпјҢйҒҝе…ҚеҗҺеҸ°жҢҒз»ӯиҜ·жұӮ
			this.stopPolling();
			this.stopHeartbeat();
			this.clearReconnectTimer();
		},
		onBackPress() {
			// д»ҺйҖҡзҹҘиҝӣе…Ҙж¶ҲжҒҜйЎөж—¶ж ҲеҸҜиғҪеҸӘжңүжң¬йЎөпјҢиҝ”еӣһж—¶еӣһеҲ°ж¶ҲжҒҜйЎөйҒҝе…Қз©әзҷҪ
			const pages = getCurrentPages();
			if (pages.length === 1) {
				uni.reLaunch({ url: '/pages/chat/chat' });
				return true;
			}
		},
		onUnload() {
			// йЎөйқўеҚёиҪҪж—¶еҪ»еә•жё…зҗҶ
			this.stopPolling();
			this.stopHeartbeat();
			this.clearReconnectTimer();
			this.safeCloseSocket();
		},
		watch: {
			sessions() {
				this.dscLoading = false
			}
		},
		methods: {
			startPolling() {
				// еҚ•дҫӢиҪ®иҜўпјҢиҝӣе…ҘеүҚе…Ҳжё…зҗҶ
				this.stopPolling();
				this.pollingTimer = setInterval(() => {
					if (uni.getStorageSync('newchatMsg') === true) {
						this.getNewList();
						uni.setStorageSync("newchatMsg", false);
					}
					if (uni.getStorageSync('token') && uni.getStorageSync('newLoginMsg') === true) {
						this.isShowList = true;
					} else {
						this.isShowList = false;
					}
				}, this.pollingInterval);
			},
			stopPolling() {
				if (this.pollingTimer) {
					clearInterval(this.pollingTimer);
					this.pollingTimer = null;
				}
			},
			clearReconnectTimer() {
				if (this.reconnectTimer) {
					clearTimeout(this.reconnectTimer);
					this.reconnectTimer = null;
				}
			},
			stopHeartbeat() {
				if (this.heartbeatTimer) {
					clearInterval(this.heartbeatTimer);
					this.heartbeatTimer = null;
				}
			},
			clearReconnectTimer() {
				if (this.reconnectTimer) {
					clearTimeout(this.reconnectTimer);
					this.reconnectTimer = null;
				}
			},
			safeCloseSocket() {
				if (this.socketTask) {
					try {
						this.socketTask.close({});
					} catch (e) {
						// ignore close errors
					}
					this.socketTask = null;
					this.is_open_socket = false;
				}
			},
			// з”ҹжҲҗдјҡиҜқзҡ„е”ҜдёҖ keyпјҢйҒҝе…ҚеңЁжЁЎжқҝдёӯдҪҝз”Ёеӯ—з¬ҰдёІжӢјжҺҘеҜјиҮҙзј–иҜ‘й”ҷиҜҜ
			getSessionKey(item, index) {
				return item.uuid || item.id || `session_${index}`;
			},
			// жҳҜеҗҰдёәеә—й“әдјҡиҜқпјҲзӮ№еҮ»иҝӣе…Ҙеә—й“әе®ўжңҚпјүпјҡйқһ type=1 жҲ– жңүжңүж•Ҳеә—й“ә idпјҲйқһ 0/2 е®ҳж–№пјүпјҢйҒҝе…Қе°ҸзЁӢеәҸжҺҘеҸЈз»ҹдёҖиҝ”еӣһ type=1 ж—¶е…ЁйғЁиҝӣзі»з»ҹж¶ҲжҒҜ
			isShopSession(item) {
				if (!item) return false;
				const sid = item.shop_id != null ? item.shop_id : item.store_id;
				const isOfficial = sid === 0 || sid === '0' || sid === 2 || sid === '2';
				return item.type != 1 || !isOfficial;
			},
			// todemo() {
			// 	uni.navigateTo({
			// 		url: '/pagesB/demo2/index'
			// 		// url:'/pagesB/demo'
			// 		// url:'/pagesB/demo2/demo2'
			// 		// url:'/pagesB/demo2/demo3'
			// 	})
			// },
			// еҜ№жҜ”е№¶еұҖйғЁжӣҙж–°дјҡиҜқеҲ—иЎЁ
			compareAndUpdateSessions(oldSessions, newSessions) {
				if (!oldSessions || !newSessions || oldSessions.length === 0) {
					// еҰӮжһңжІЎжңүж—§ж•°жҚ®пјҢзӣҙжҺҘиҝ”еӣһж–°ж•°жҚ®
					return newSessions;
				}
				
				// еҲӣе»әж—§ж•°жҚ®зҡ„жҳ е°„пјҢдҪҝз”ЁuuidжҲ–idдҪңдёәkey
				const oldMap = new Map();
				oldSessions.forEach(session => {
					const key = session.uuid || session.id;
					if (key) {
						oldMap.set(key, session);
					}
				});
				
				// еҲӣе»әж–°ж•°жҚ®зҡ„жҳ е°„
				const newMap = new Map();
				newSessions.forEach(session => {
					const key = session.uuid || session.id;
					if (key) {
						newMap.set(key, session);
					}
				});
				
				// жүҫеҮәйңҖиҰҒжӣҙж–°зҡ„дјҡиҜқпјҲе·ІеӯҳеңЁзҡ„дјҡиҜқпјү
				const updatedSessions = [];
				const newSessionsList = [];
				
				// йҒҚеҺҶж–°ж•°жҚ®пјҢеҲӨж–ӯжҳҜжӣҙж–°иҝҳжҳҜж–°еўһ
				newSessions.forEach(newSession => {
					const key = newSession.uuid || newSession.id;
					if (!key) {
						newSessionsList.push(newSession);
						return;
					}
					
					const oldSession = oldMap.get(key);
					if (oldSession) {
						// жЈҖжҹҘжҳҜеҗҰжңүеҸҳеҢ–
						const hasChanged = 
							oldSession.last_message !== newSession.last_message ||
							oldSession.last_time !== newSession.last_time ||
							oldSession.unread !== newSession.unread ||
							oldSession.shop_name !== newSession.shop_name ||
							oldSession.store_id !== newSession.store_id;
						
						if (hasChanged) {
							// жңүеҸҳеҢ–пјҢйңҖиҰҒжӣҙж–°
							updatedSessions.push({
								key: key,
								oldIndex: oldSessions.findIndex(s => (s.uuid || s.id) === key),
								newData: newSession
							});
						}
					} else {
						// ж–°дјҡиҜқпјҢж·»еҠ еҲ°ж–°еҲ—иЎЁ
						newSessionsList.push(newSession);
					}
				});
				
				// жүҫеҮәйңҖиҰҒеҲ йҷӨзҡ„дјҡиҜқпјҲж—§ж•°жҚ®дёӯеӯҳеңЁдҪҶж–°ж•°жҚ®дёӯдёҚеӯҳеңЁпјү
				const deletedKeys = [];
				oldMap.forEach((oldSession, key) => {
					if (!newMap.has(key)) {
						deletedKeys.push(key);
					}
				});
				
				// еҰӮжһңжңүжӣҙж–°гҖҒж–°еўһжҲ–еҲ йҷӨпјҢиҝ”еӣһtrueиЎЁзӨәйңҖиҰҒжӣҙж–°
				if (updatedSessions.length > 0 || newSessionsList.length > 0 || deletedKeys.length > 0) {
					return {
						needUpdate: true,
						updatedSessions: updatedSessions,
						newSessions: newSessionsList,
						deletedKeys: deletedKeys,
						allNewSessions: newSessions // еҰӮжһңеҸҳеҢ–иҫғеӨ§пјҢзӣҙжҺҘдҪҝз”Ёж–°ж•°жҚ®
					};
				}
				
				// жІЎжңүеҸҳеҢ–
				return {
					needUpdate: false,
					allNewSessions: oldSessions
				};
