			// иҺ·еҸ–ж–°ж¶ҲжҒҜеҲ—иЎЁпјҲеёҰзј“еӯҳе’ҢеұҖйғЁжӣҙж–°пјү
			// иҒҢиҙЈпјҡеҸӘиҙҹиҙЈиҪ»йҮҸзә§зҡ„е®ҡж—¶еҲ·ж–°пјҢдёҚйҮҚж–°еҠ иҪҪе®Ңж•ҙж•°жҚ®
			getNewList() {
				var that = this
				
				// е№¶еҸ‘й”ҒдёҺиҠӮжөҒ
				const now = Date.now();
				if (that.isFetchingNewList) {
					return;
				}
				if (now - that.lastNewListTs < that.newListMinInterval) {
					return;
				}
				that.lastNewListTs = now;
				that.isFetchingNewList = true;
				
				// еҰӮжһңжІЎжңүж•°жҚ®пјҢзӣҙжҺҘиҝ”еӣһпјҢдёҚеҠ иҪҪж•°жҚ®пјҲз”ұgoodsListиҙҹиҙЈе®Ңж•ҙеҠ иҪҪпјү
				if (that.sessions.length === 0) {
					that.isFetchingNewList = false;
					return;
				}
				
				// иҜ»еҸ–зј“еӯҳ
				const cachedData = uni.getStorageSync('chat_sessions_cache');
				const cacheTime = uni.getStorageSync('chat_sessions_cache_time');
				const CACHE_EXPIRE_TIME = 3 * 60 * 1000; // 3еҲҶй’ҹзј“еӯҳ
				const isCacheExpired = cacheTime && (Date.now() - cacheTime > CACHE_EXPIRE_TIME);
				
				uni.request({
					url: this.websiteUrl + '/api/chat/sessionsnew',
					method: 'GET',
					data: {
						page: 1,
						size: 10
					},
					header: {
						'Content-Type': 'application/json',
						'token': uni.getStorageSync('token'),
						'X-Client-Hash': uni.getStorageSync('client_hash')
					},
					success: (res) => {
						this.onelist = []
						if (res.data.status == 'success') {
							this.loading1 = false
							if (res.data.data.length > 0) {
								// еҰӮжһңжңүзј“еӯҳдё”жңӘиҝҮжңҹпјҢиҝӣиЎҢеұҖйғЁжӣҙж–°
								if (cachedData && !isCacheExpired && that.sessions.length > 0) {
									const updateResult = that.compareAndUpdateSessions(that.sessions, res.data.data);
									if (!updateResult.needUpdate) {
										return;
									}
									
									// ж•°жҚ®жңүеҸҳеҢ–пјҢиҝӣиЎҢеұҖйғЁжӣҙж–°
									if (updateResult.updatedSessions && updateResult.updatedSessions.length > 0) {
										// жӣҙж–°е·ІеӯҳеңЁзҡ„дјҡиҜқ
										updateResult.updatedSessions.forEach(({ key, oldIndex, newData }) => {
											if (oldIndex !== -1) {
												// дҪҝз”Ё$setзЎ®дҝқе“Қеә”ејҸжӣҙж–°
												Object.keys(newData).forEach(prop => {
													that.$set(that.sessions[oldIndex], prop, newData[prop]);
												});
											}
										});
									}
									
									// ж·»еҠ ж–°дјҡиҜқеҲ°йЎ¶йғЁпјҲеҺ»йҮҚпјҢйҒҝе…ҚйҮҚеӨҚпјү
									if (updateResult.newSessions && updateResult.newSessions.length > 0) {
										// иҺ·еҸ–зҺ°жңүдјҡиҜқзҡ„keyйӣҶеҗҲ
										const existingKeys = new Set(that.sessions.map(s => s.uuid || s.id));
										// иҝҮж»ӨжҺүе·ІеӯҳеңЁзҡ„дјҡиҜқ
										const trulyNewSessions = updateResult.newSessions.filter(s => {
											const key = s.uuid || s.id;
											return key && !existingKeys.has(key);
										});
										if (trulyNewSessions.length > 0) {
											that.sessions = trulyNewSessions.concat(that.sessions);
										}
									}
									
									// еҲ йҷӨдёҚеӯҳеңЁзҡ„дјҡиҜқ
									if (updateResult.deletedKeys && updateResult.deletedKeys.length > 0) {
										that.sessions = that.sessions.filter(s => {
											const key = s.uuid || s.id;
											return !updateResult.deletedKeys.includes(key);
										});
									}
									
									// еҰӮжһңеҸҳеҢ–иҫғеӨ§пјҢзӣҙжҺҘдҪҝз”Ёж–°ж•°жҚ®
									if (updateResult.updatedSessions.length > 5 || updateResult.newSessions.length > 3) {
										that.sessions = res.data.data;
									}
								} else {
									// жІЎжңүзј“еӯҳжҲ–е·ІиҝҮжңҹпјҢзӣҙжҺҘдҪҝз”Ёж–°ж•°жҚ®
									this.$nextTick(() => {
										this.sessions = this.onelist.concat(res.data.data)
									})
								}
								
								// жӣҙж–°зј“еӯҳ
								uni.setStorageSync('chat_sessions_cache', res.data.data);
								uni.setStorageSync('chat_sessions_cache_time', Date.now());
							} else {
								this.sessions = []
							}
						} else {
							this.loading1 = false
							// еҰӮжһңиҜ·жұӮеӨұиҙҘдҪҶжңүзј“еӯҳпјҢдҪҝз”Ёзј“еӯҳ
							if (cachedData && !isCacheExpired && that.sessions.length === 0) {
								that.sessions = cachedData;
							} else {
								this.sessions = []
							}
						}
						that.isFetchingNewList = false;
					},
					fail: (err) => {
						// иҜ·жұӮеӨұиҙҘпјҢеҰӮжһңжңүзј“еӯҳдё”жңӘиҝҮжңҹпјҢдҪҝз”Ёзј“еӯҳ
						if (cachedData && !isCacheExpired && that.sessions.length === 0) {
							that.sessions = cachedData;
							that.loading1 = false;
						} else {
							that.loading1 = false;
							that.sessions = [];
						}
						that.isFetchingNewList = false;
					}
				})
			},

			toLogin() {
