								const cachedData = uni.getStorageSync('chat_sessions_cache');
								const cacheTime = uni.getStorageSync('chat_sessions_cache_time');
								const CACHE_EXPIRE_TIME = 3 * 60 * 1000;
								const isCacheExpired = cacheTime && (Date.now() - cacheTime > CACHE_EXPIRE_TIME);
								
								if (res.data.data.length > 0) {
									// иҺ·еҸ– kefuLoginData з”ЁдәҺ WebSocket иҝһжҺҘ
									if (res.data.data[0] && res.data.data[0].token) {
										uni.request({
											url: this.websiteUrl + '/kefu/index',
