									// еҰӮжһңжңүзј“еӯҳдё”жңӘиҝҮжңҹпјҢиҝӣиЎҢеұҖйғЁжӣҙж–°
									if (cachedData && !isCacheExpired && that.sessions.length > 0) {
										const updateResult = that.compareAndUpdateSessions(that.sessions, res.data.data);
										if (!updateResult.needUpdate) {
