										// ж•°жҚ®жңүеҸҳеҢ–пјҢиҝӣиЎҢеұҖйғЁжӣҙж–°
										if (updateResult.updatedSessions && updateResult.updatedSessions.length > 0) {
											updateResult.updatedSessions.forEach(({ key, oldIndex, newData }) => {
												if (oldIndex !== -1) {
													Object.keys(newData).forEach(prop => {
